import SwiftUIimport FirebaseCore@mainstruct NearEarthObjectsApp: App {    @StateObject private var authVM = AuthViewModel()    init() {        FirebaseApp.configure()    }    var body: some Scene {        WindowGroup {            if authVM.isLoggedIn {                NEOListView()                    .preferredColorScheme(.dark)                    .environmentObject(authVM)            } else {                AuthView()                    .preferredColorScheme(.dark)                    .environmentObject(authVM)            }        }    }}